import { ethers } from 'ethers';

const app = new ethers.App();

// Get the user's wallet address
const walletAddress = await app.getWalletAddress();

// Create a transaction object with the user's wallet address and the contract address
const tx = {
  from: walletAddress,
  to: '0x...', // Replace with the contract address
  value: ethers.utils.parseEther('1'), // Replace with the amount of ETH to send
};

// Sign the transaction using the user's private key
const signedTx = await app.signTransaction(tx);

// Send the signed transaction to the network
await app.sendSignedTransaction(signedTx);